```javascript
function solve(nums) {
    const n = nums.length;
    for (let p = 1; p <= n - 3; p++) {
        for (let q = p + 1; q <= n - 2; q++) {
            // Check first part: 0 to p is strictly increasing
            let isIncreasingFirst = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    isIncreasingFirst = false;
                    break;
                }
            }
            if (!isIncreasingFirst) continue;

            // Check middle part: p to q is strictly decreasing
            let isDecreasingMiddle = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    isDecreasingMiddle = false;
                    break;
                }
            }
            if (!isDecreasingMiddle) continue;

            // Check last part: q to end is strictly increasing
            let isIncreasingLast = true;
            for (let i = q; i < n - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    isIncreasingLast = false;
                    break;
                }
            }
            if (isIncreasingLast) {
                return true;
            }
        }
    }
    return false;
}
```

