    function isStrictlyIncreasing(start, end) {
        for (let i = start; i < end; i++) {
            if (nums[i] >= nums[i + 1]) return false;
        }
        return true;
    }

    function isStrictlyDecreasing(start, end) {
        for (let i = start; i < end; i++) {
            if (nums[i] <= nums[i + 1]) return false;
        }
        return true;
    }

    for (let p = 1; p <= n - 3; p++) {
        for (let q = p + 1; q <= n - 2; q++) {
            if (isStrictlyIncreasing(0, p) && 
                isStrictlyDecreasing(p, q) && 
                isStrictlyIncreasing(q, n - 1)) {
                return true;
            }
        }
    }
    return false;
}
